changeSet.sql:
INSERT INTO permissions (name, description) VALUES ('plugin_itam_view', 'View ITAM logs');
INSERT INTO userRolePermissions (roleId, permissionId)
    SELECT id, currval('permissions_id_seq') FROM userRoles;

INSERT INTO permissions (name, description) VALUES ('plugin_itam_create', 'Create ITAM log entries');
INSERT INTO userRolePermissions (roleId, permissionId)
    SELECT id, currval('permissions_id_seq') FROM userRoles;

INSERT INTO permissions (name, description) VALUES ('plugin_itam_delete', 'Delete ITAM log entries');
INSERT INTO userRolePermissions (roleId, permissionId)
    SELECT id, currval('permissions_id_seq') FROM userRoles;

INSERT INTO permissions (name, description) VALUES ('plugin_itam_export', 'Export ITAM logs to CSV');
INSERT INTO userRolePermissions (roleId, permissionId)
    SELECT id, currval('permissions_id_seq') FROM userRoles;

DELETE FROM userRolePermissions
WHERE permissionId IN (
    SELECT id FROM permissions
    WHERE name IN ('plugin_itam_view', 'plugin_itam_create', 'plugin_itam_delete', 'plugin_itam_export')
);

changeSet.rollback:
INSERT INTO userRolePermissions (roleId, permissionId)
    SELECT r.id, p.id FROM userRoles r, permissions p
    WHERE p.name IN ('plugin_itam_view', 'plugin_itam_create', 'plugin_itam_delete', 'plugin_itam_export');

changeSet.sql:
INSERT INTO userRolePermissions (roleId, permissionId)
    SELECT 2, id FROM permissions
    WHERE name IN ('plugin_itam_view', 'plugin_itam_create', 'plugin_itam_delete', 'plugin_itam_export');

changeSet.rollback:
DELETE FROM userRolePermissions
WHERE roleId = 2 AND permissionId IN (
    SELECT id FROM permissions
    WHERE name IN ('plugin_itam_view', 'plugin_itam_create', 'plugin_itam_delete', 'plugin_itam_export')
);
